import Link from "next/link";
import { listJobs } from "@/lib/queries";
import type { Job } from "@/lib/schema";

export const dynamic = "force-dynamic";

function fmt(ts: number | null) {
  return ts ? new Date(ts).toLocaleString() : "—";
}

function badge(s: Job["status"]) {
  const cls =
    s === "succeeded" ? "green" :
    s === "failed" ? "red" :
    s === "running" ? "blue" : "amber";
  return <span className={`badge ${cls}`}>{s}</span>;
}

export default async function JobsPage() {
  const jobs = await listJobs(300);
  return (
    <>
      <h1>Jobs</h1>
      <div className="card" style={{ padding: 0 }}>
        <table>
          <thead>
            <tr>
              <th>Host</th>
              <th>Type</th>
              <th>Status</th>
              <th>Exit</th>
              <th>Created</th>
              <th>Finished</th>
            </tr>
          </thead>
          <tbody>
            {jobs.length === 0 && (
              <tr><td colSpan={6} className="empty">No jobs yet.</td></tr>
            )}
            {jobs.map((j) => (
              <tr key={j.id}>
                <td>
                  <Link href={`/instances/${j.instanceId}`}>
                    {j.hostname ?? j.instanceId.slice(0, 8)}
                  </Link>
                </td>
                <td>{j.type}</td>
                <td>{badge(j.status)}</td>
                <td className="muted">{j.exitCode ?? "—"}</td>
                <td className="muted">{fmt(j.createdAt)}</td>
                <td className="muted">{fmt(j.finishedAt)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}
